#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int A,B,P,Q; scanf("%d %d %d %d", &A, &B, &P, &Q);
        if(A==P && B==Q){
            printf("0\n");
        }else if( ((A+B)&1) != ((P+Q)&1) ){
            printf("1\n");
        }else{
            printf("2\n");
        }
    }
    return 0;
}

